--
-- Table structure for table `caipiao_game_bet`
--

DROP TABLE IF EXISTS `caipiao_game_bet`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_game_bet` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `order_no` varchar(50) NOT NULL COMMENT 'Mã đơn',
  `uid` int(11) NOT NULL COMMENT 'ID người dùng',
  `platform` varchar(20) NOT NULL COMMENT 'Mã nền tảng',
  `platform_name` varchar(50) DEFAULT '' COMMENT 'Tên nền tảng',
  `game_id` varchar(50) NOT NULL COMMENT 'ID trò chơi',
  `game_name` varchar(100) DEFAULT '' COMMENT 'Tên trò chơi',
  `game_type` varchar(20) DEFAULT 'slot',
  `bet_amount` decimal(15,2) NOT NULL COMMENT 'Số tiền cược',
  `valid_amount` decimal(15,2) DEFAULT '0.00',
  `bet_content` text,
  `win_amount` decimal(15,2) DEFAULT '0.00' COMMENT 'Tiền thắng',
  `profit` decimal(15,2) DEFAULT '0.00' COMMENT 'Lãi lỗ',
  `status` varchar(20) DEFAULT 'pending' COMMENT 'Trạng thái: pending-chờ thanh toán, settled-đã thanh toán, cancelled-đã hủy',
  `bet_time` int(11) NOT NULL COMMENT 'Thời gian cược',
  `settle_time` int(11) DEFAULT '0' COMMENT 'Thời gian thanh toán',
  `created_at` int(11) NOT NULL,
  `updated_at` int(11) DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_order_no` (`order_no`),
  KEY `idx_uid` (`uid`),
  KEY `idx_platform` (`platform`),
  KEY `idx_bet_time` (`bet_time`)
) ENGINE=InnoDB AUTO_INCREMENT=40 DEFAULT CHARSET=utf8mb4 COMMENT='Lịch sử đặt cược';
/*!40101 SET character_set_client = @saved_cs_client */;

